import type { JSX, ReactNode, RefObject } from 'react';
import type { MessageDescriptor } from 'react-intl';

import type { Store } from '../../../../core/store/store.js';
import type { TruncationMode } from '../../../../typography/text-ellipsis/TextEllipsis.js';

/** @internal */
export const enum GeometryTypesEnum {
  'dot' = 'dot',
  'line' = 'line',
  'area' = 'area',
  'bar' = 'bar',
  'pie' = 'pie',
  'meterbar' = 'meterbar',
  'multimeterbar' = 'multimeterbar',
  'treemap' = 'treemap',
  'rect' = 'rect',
  'honeycomb' = 'honeycomb',
  'geoBubble' = 'geoBubble',
  'geoChoropleth' = 'geoChoropleth',
  'geoConnection' = 'geoConnection',
  'geoDot' = 'geoDot',
}

/** @internal */
export type GeometryTypes = keyof typeof GeometryTypesEnum;

/** @internal */
export type Positions =
  | {
      absoluteX: number;
      absoluteY: number;
      relativeX: number;
      relativeY: number;
      percentX: number;
      percentY: number;
    }
  | {
      absoluteX: null;
      absoluteY: null;
      relativeX: null;
      relativeY: null;
      percentX: null;
      percentY: null;
    };
/** @internal */
export type Overlay = {
  overlayRef: RefObject<HTMLDivElement>;
  getBounds: () => DOMRect | undefined;
  getAdjustedPositionsFromRelative: (
    relativeX: number,
    relativeY: number,
  ) => Positions;
  getAdjustedPositionsFromAbsolute: (
    absoluteX: number,
    absoluteY: number,
  ) => Positions;
  getAdjustedPositionsFromPercent: (
    percentX: number,
    percentY: number,
    relativeX?: number,
    relativeY?: number,
  ) => Positions;
  clear: () => void;
};

/** @internal */
export type TooltipState = {
  activeSeries: string | null;
  pinned: boolean;
  inBounds: boolean;
  data: Data | NoData;
} & Positions;

/**  @internal  */
export type TooltipStore = Store<TooltipState>;

/**
 * A primitive value that can appear in a tooltip header or series row.
 * @public
 */
export type TooltipValue = string | number | Date | undefined;
/**
 * The display name for a data series.
 * Pass a `string[]` to enable multi-line rendering.
 * @public
 */
export type SeriesName = string | string[];
/**
 * The value(s) displayed in a tooltip header row.
 * - `TooltipValue` — single value.
 * - `[TooltipValue]` — single value as a tuple.
 * - `[TooltipValue, TooltipValue]` — a from/to range pair.
 * - `[]` — explicitly empty (no header value).
 * @public
 */
export type HeaderData =
  | []
  | [TooltipValue]
  | [TooltipValue, TooltipValue]
  | TooltipValue;
/**  @internal  */
export type Geometry = GeometryTypesEnum;
/**  @internal  */
export type Data = {
  metadata?: unknown;
  geometry: GeometryTypes;
  header1?: HeaderData;
  subheader?: HeaderData;
  series: {
    name: SeriesName;
    value: string | number | Date;
    color: string;
    valueUnit?: string;
    relativeValue?: string | number;
    relativeValueUnit?: string;
  }[];
};
/** @internal */
export type NoData = {
  metadata?: undefined;
  header1: undefined;
  series: undefined;
  subheader: undefined;
  geometry: 'none';
};

/** @internal */
export interface DefaultConfig {
  headerLabel?: MessageDescriptor;
  symbolPosition?: 'left' | 'right';
  seriesLabel: MessageDescriptor;
  valueLabel: MessageDescriptor;
  headerShowRangeDuration?: boolean;
  headerFormatStrategy?: FormatStrategy;
  truncationMode?: TruncationMode;
  sharedVariant?: boolean;
  defaultActionsConfig: Map<
    string,
    {
      field: 'seriesLabel' | 'valueLabel';
      messageLabel?: MessageDescriptor;
      customLabel?: string;
    }
  >;
}

/** @internal */
export type DefaultConfigByGeometry = Record<Geometry, DefaultConfig>;

/** @internal */
export type GeoLayerTypes = 'bubble' | 'choropleth' | 'connection' | 'dot';

/** @internal */
export type DefaultConfigByGeoLayer = Record<GeoLayerTypes, DefaultConfig>;

/** @internal */
export type ExternalConfig = {
  seriesHeader: JSX.Element | null;
  displayHeaderDivider: boolean;
  symbolPosition: 'left' | 'right' | undefined;
  truncationMode: TruncationMode;
  defaultActionsConfig: DefaultConfig['defaultActionsConfig'];
  variant: 'shared' | 'single';
};

/** @internal */
export type OverlayTooltipBaseProps = {
  /** Overrides the horizontal alignment of series symbols. */
  symbolAlignment?: 'left' | 'right';
  legacyTemplate?: ReactNode;
  /**
   * The truncation mode to use when the text exceeds the available space.
   * @defaultValue 'end'
   */
  truncation?: TruncationMode;
};

/** @internal */
export type OverlayTooltipUncontrolledProps = OverlayTooltipBaseProps & {
  absoluteX?: never;
  absoluteY?: never;
  isInteractive?: never;
};

/** @internal */
export type OverlayTooltipControlledProps = OverlayTooltipBaseProps & {
  /** Absolute X position (pixels) for static tooltip placement. */
  absoluteX: number;
  /** Absolute Y position (pixels) for static tooltip placement. */
  absoluteY: number;
  /** Whether the tooltip should be interactive (enables pointer events). */
  isInteractive: boolean;
};

/** @internal */
export type OverlayTooltipProps =
  | OverlayTooltipUncontrolledProps
  | OverlayTooltipControlledProps;

/**
 * Props for `OverlayTooltip.Header`, which renders the primary header text row.
 * @public
 */
export type HeaderProps = {
  /** The header text to display. */
  text?: string;
  /** Maximum width in pixels before truncation. If not provided, uses container width. */
  maxWidth?: number;
};

/**
 * Props for `OverlayTooltip.SeriesHeader`, which renders the column label row
 * above the series entries.
 * @public
 */
export type SeriesHeaderProps = {
  /** The series label text. */
  seriesLabel?: string;
  /** The value label text. */
  valueLabel?: string;
  /** Whether to hide the series header. */
  disabled?: boolean;
};

/** @internal */
export type FormatStrategy = (value: HeaderData) => string | null;

/** @internal */
export type TooltipAction =
  | { type: 'RESET_TOOLTIP' }
  | {
      type: 'SET_PINNED';
      payload:
        | {
            pinned: false;
            absoluteX?: undefined;
            absoluteY?: undefined;
            data: NoData;
          }
        | {
            pinned: true;
            absoluteX: number;
            absoluteY: number;
            data: Data;
          };
    }
  | { type: 'SET_OUT_BOUNDS' }
  | {
      type: 'SET_POSITION';
      payload: { absoluteX: number; absoluteY: number; data?: Data };
    }
  | {
      type: 'UPDATE_POSITION';
      payload: { type: 'resize' | 'non-resize'; scroll?: boolean };
    }
  | {
      type: 'SET_ACTIVE_SERIES';
      payload: { activeSeries: string | null };
    }
  | { type: 'TOOLTIP_MOUSE_LEAVE' };

/** @internal */
export type TooltipActions = TooltipAction['type'];
